using System.Collections.Generic; public static class JournalTextBuilder { public static string Build(IReadOnlyList<QuestDefinition> quests,PlayerInventoryState inventory,BaseStorageState storage){ if(quests==null||quests.Count==0)return "Активных целей нет."; List<string> lines=new(); foreach(QuestDefinition q in quests){ int amount=0; if(inventory!=null)amount+=inventory.GetTotalAmount(q.TargetItemId); if(storage!=null)amount+=storage.GetTotalAmount(q.TargetItemId); string mark=amount>=q.TargetAmount?"✓":"•"; lines.Add($"{mark} {q.Title}: {amount}/{q.TargetAmount} — {q.Description}"); } return string.Join("\n",lines); } }